export function generateLetterVersions(data: LetterData, toneIndex: number = 0) {
  const { sender, recipient, content } = data;
  const sets = multiVersionTemplates[content.type] || multiVersionTemplates['Job Application'];
  const set = sets[toneIndex % sets.length];

  const processTemplate = (text: string) => {
    let result = text;
    // Date
    result = result.replace(/\[DATE\]/g, new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }));
    
    // Basic replacements
    result = result.replace(/\[JOB_TITLE\]/g, recipient.title || 'your role');
    result = result.replace(/\[COMPANY_NAME\]/g, recipient.company || 'your organization');
    result = result.replace(/\[RECIPIENT_COMPANY\]/g, recipient.company || 'the organization');
    result = result.replace(/\[SENDER_NAME\]/g, sender.name || 'SENDER NAME');
    result = result.replace(/\[SENDER_TITLE\]/g, sender.title || 'Professional');
    result = result.replace(/\[SENDER_PHONE\]/g, sender.phone || '');
    result = result.replace(/\[RECIPIENT_NAME\]/g, recipient.name || 'Recipient Name');
    result = result.replace(/\[RECIPIENT_ADDRESS\]/g, recipient.address || 'Recipient Address');
    result = result.replace(/\[COUNTRY_NAME\]/g, content.situationalAnswers.destination || recipient.address || 'the destination');

    // Scholarship specific
    result = result.replace(/\[SCHOLARSHIP_NAME\]/g, content.situationalAnswers.scholarshipName || 'the requested scholarship');

    // Situational replacements
    Object.entries(content.situationalAnswers).forEach(([id, value]) => {
      const key = `[SITUATION_${id.toUpperCase()}]`;
      const replacement = value || `... (specify ${id.replace(/_/g, ' ')})`;
      result = result.replace(new RegExp(key.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'), replacement);
    });

    // Cleanup any remaining SITUATION tags
    result = result.replace(/\[SITUATION_[A-Z_]+\]/g, '...');
    
    return result;
  };

  return {
    short: processTemplate(set.short),
    detailed: processTemplate(set.detailed),
    email: `Subject: ${processTemplate(set.emailSubject)}\n\n${processTemplate(set.emailBody)}`
  };
}
